('networking-foundations', NULL, 'phase', NULL, NULL, NULL, 'Networking Foundations', 'Start with how networks move data, how devices communicate, and how to build a safe lab environment.', 'This phase builds the networking foundations layer of the Network Engineer path.', 1, 'trunk', 'networking-foundations', 1, 0, 32, 'beginner', 99, '{"phase": 1, "isVisual": true}'::jsonb, true, false, '["Complete the major learning goals for Networking Foundations."]'::jsonb, '["All required child nodes for Networking Foundations are completed."]'::jsonb),
